(15,106737,NULL,'2024-06-13 07:57:44','2024-07-28 01:16:42','{\"id\":106737,\"name\":\"G03\",\"title\":\"Listen and Choose the correct awnser\",\"description\":\"Điền từ còn thiếu vào ô trống\",\"duration\":0,\"platform\":{\"id\":376,\"description\":\"Dạng câu hỏi đoạn văn\",\"code\":\"3\",\"isActive\":true,\"createdAt\":\"2024-06-04T18:23:38.000Z\",\"updatedAt\":\"2024-06-13T18:59:34.000Z\"},\"skill\":\"READING\",\"content\":{\"text\":\"Hello, I\'m Tan, a Credit Analyst. I work for Military Commercial Joint Stock Bank in Vietnam. Our bank is well-known for providing great financial services. Our head office is based in Hanoi, where we operate many branches. I specialize in analyzing financial data of people who want to borrow money from the bank. We invest time in understanding our customers so that we can offer them the best thing we have. Our bank tries very hard to support our customers. I like my job because I get to help people manage their money. Thank you for listening. Have a nice day!\",\"audio\":{\"id\":115,\"filePath\":\"/uploads/2024/07/02/1719882090_Hello, I\'m Tan, a Credit Analyst. I work for Military Commercial Joint Stock Bank in Vietnam. Our bank is well-known for providing great financial services. Our head office is based in Hanoi, where we operate many .mp3\"}},\"hint\":{\"text\":null},\"answerHelp\":{\"text\":null},\"subQuestions\":[{\"content\":{\"bot\":null,\"title\":\"Q1.1 1. What does Tan do?\",\"text\":\"\",\"vnTitle\":\"\",\"pronunciation\":\"\",\"image\":null,\"audio\":null,\"video\":null},\"explanation\":{\"text\":\"Nước hình chữ S\"},\"message\":{\"correct\":\"Good job!!!\",\"wrong\":\"Ba ke à???\"},\"answers\":[{\"text\":\"a bank clerk\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"1\"},{\"text\":\"a credit card\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"},{\"text\":\"a credit analyst\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"}]},{\"content\":{\"bot\":null,\"title\":\"Q1.2: Who does he work for?\",\"text\":\"\",\"vnTitle\":\"\",\"pronunciation\":\"\",\"image\":null,\"audio\":null,\"video\":null},\"explanation\":{\"text\":\"Bà mẹ VN anh hùng\"},\"message\":{\"correct\":\"Excellent\",\"wrong\":\"Bất hiếu quớ\"},\"answers\":[{\"text\":\"a bank in Vietnam\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"},{\"text\":\"the Military\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"},{\"text\":\"a commercial company\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"1\"}]}]}'),
(16,106738,NULL,'2024-06-13 08:05:53','2024-07-28 01:16:42','{\"id\":106738,\"name\":\"G17\",\"title\":\"Read the Passage and Choose the correct awnser\",\"description\":\"Đọc đoạn văn, chọn đáp án đúng\",\"duration\":0,\"platform\":{\"id\":388,\"description\":\"Đoạn văn - Điền vào chỗ trống\",\"code\":\"7\",\"isActive\":true,\"createdAt\":\"2024-06-11T17:56:48.000Z\",\"updatedAt\":\"2024-06-13T19:00:29.000Z\"},\"skill\":\"READING\",\"content\":{\"text\":\"My mother is a person I admire most. She devoted a lot of time and energy  to the upbringing of my two brothers and 1. Despite working hard, she  always made time to teach us many  useful things which are necessary and  important in our later lives. Moreover, she is a good role model for me to  follow. She always tries to get on well with people who live next door and  help everyone when they are in  difficulties, so most of them respect  and love her. I admire and look up to  my mother because she not only  brings me up well but also stands by  me and gives some help if necessary. For example, when I encounter some  difficulties, she will give me some  precious advice to help me solve those  problems. She has a major influence  on me and 1 hope that I will inherit  some of her traits.\"},\"hint\":{\"text\":null},\"answerHelp\":{\"text\":null},\"subQuestions\":[{\"content\":{\"bot\":null,\"title\":\"Q1.1 Where is she from?\",\"text\":\"\",\"vnTitle\":\"\",\"pronunciation\":\"\",\"image\":null,\"audio\":null,\"video\":null},\"explanation\":{\"text\":\"S shaped country\"},\"message\":{\"correct\":\"Bravo\",\"wrong\":\"Ba que hả?\"},\"answers\":[{\"text\":\"Laos\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"},{\"text\":\"Vietnam\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"1\"},{\"text\":\"USA\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"},{\"text\":\"Canada\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"}]},{\"content\":{\"bot\":null,\"title\":\"2. Who is her mother?\",\"text\":\"\",\"vnTitle\":\"\",\"pronunciation\":\"\",\"image\":null,\"audio\":null,\"video\":null},\"explanation\":{\"text\":\"Mẹ cô ấy là người\"},\"message\":{\"correct\":\"Gooooood Job!!!!\",\"wrong\":\"Eeeeeeh\"},\"answers\":[{\"text\":\"A man\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"},{\"text\":\"A person\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"1\"},{\"text\":\"A lady boy\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"},{\"text\":\"Superhero\",\"pronunciation\":\"\",\"vnTitle\":\"\",\"timeout\":0,\"position\":0,\"image\":null,\"audio\":null,\"rightResponse\":\"-1\"}]}]}'),
