(64,106771,NULL,'2024-07-24 14:32:01','2024-08-08 08:37:03','{\"id\":106771,\"name\":\"G15\",\"title\":\"Read the suggestions and complete the  passage in the Question\",\"description\":\"Điền từ và nói\",\"duration\":0,\"platform\":{\"id\":385,\"description\":\"Ghi âm\",\"code\":\"15\",\"isActive\":true,\"createdAt\":\"2024-06-11T06:51:44.000Z\",\"updatedAt\":\"2024-06-11T06:51:44.000Z\"},\"skill\":\"SPEAKING\",\"content\":{\"text\":\"<p><strong>(1) Tên người bạn muốn nói chuyện</strong>&nbsp;</p><p>(2) Tên của bạn&nbsp;</p><p>(3) đánh vần tên của bạn&nbsp;</p><p>(4) tên công ty của bạn&nbsp;</p><p>(5) đánh vần tên công ty của bạn&nbsp;</p><p>(6) mục đích của cuộc gọi này&nbsp;</p><p>VD: provide feedback on the customer service I received from your company. discuss potential partnership opportunities between our companies. arrange a meeting with a representative from your company.&nbsp;</p><p>(7) số điện thoại của bạn (8) nghề nghiệp của bạn</p>\"},\"hint\":{\"text\":null},\"answerHelp\":{\"text\":null},\"subQuestions\":[{\"content\":{\"bot\":null,\"title\":\"Hoàn thành đoạn hội thoại và tập nói.\",\"text\":\"Topic: You call someone but he/she is busy. Leave him a message.\\n\\nA: Hello, Tech solutions Corporation. How can I help you?\\nB: Hi, could I speak to [...], please?\\nA: May I have your name, please?\\nB: This is [...].\\nA: Could you please spell your name for me?\\nB: Sure, it\'s [...] .\\nA: Thank you. And where are you calling from, Mark?\\nB: I\'m calling from [...].\\nA: Could you spell it for me, please?\\nB: It\'s [...].\\nA: Thank you. How can I help you?\\nB: I\'m phoning to [...].\\nA: I\'m sorry, but he/she is currently unavailable. Can I take a message?\\nB: Yes, could you please ask him/her to call me back?\\nA: Of course. Could I have your contact details, please?\\nB: Sure, my phone number is [...].\\nA: Got it. Thanks. And what is your position at Zenith Marketing Hive?\\nB: I am [...].\\nA: I\'ll give him/her your message and contact details.\\nB: Thank you very much for your help.\\nA: You\'re welcome, Mark. Have a great day!\\nB: You too, goodbye.\",\"vnTitle\":\"\",\"pronunciation\":\"\",\"image\":null,\"audio\":null,\"video\":null},\"explanation\":{\"text\":\"\"},\"message\":{\"correct\":\"\",\"wrong\":\"\"},\"answers\":[]}]}'),
