CREATE TABLE `gb_questions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `duration` int(11) DEFAULT NULL,
  `metadata_version` varchar(255) DEFAULT NULL,
  `description` varchar(255) DEFAULT NULL,
  `response_interaction_type` varchar(255) DEFAULT 'NONE',
  `question_content` text DEFAULT NULL,
  `answers` text DEFAULT NULL,
  `platform_id` int(11) DEFAULT NULL,
  `topic_id` int(11) DEFAULT NULL,
  `skill_verb_id` int(11) DEFAULT NULL,
  `level` int(11) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `content_text` text DEFAULT NULL,
  `content_image` varchar(10) DEFAULT NULL,
  `content_audio` varchar(200) DEFAULT NULL,
  `content_video` varchar(100) DEFAULT NULL,
  `sub_questions_ids` varchar(100) DEFAULT NULL,
  `answer_help_text` text DEFAULT NULL,
  `answer_help_image` varchar(100) DEFAULT NULL,
  `answer_help_audio` varchar(100) DEFAULT NULL,
  `answer_help_video` varchar(100) DEFAULT NULL,
  `hint_text` text DEFAULT NULL,
  `hint_image` varchar(100) DEFAULT NULL,
  `hint_video` varchar(100) DEFAULT NULL,
  `hint_audio` varchar(100) DEFAULT NULL,
  `bot` int(11) DEFAULT NULL,
  `skill` varchar(100) DEFAULT NULL,
  `title` varchar(100) DEFAULT NULL,
  `is_practice` int(11) DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=106837 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
