(9,'answer','hỏi',1,NULL,'2024-07-29 07:20:47','2024-08-12 09:29:30','to inquire or request information','(v)','/ˈɑːnsə(r)/','<p><style type=\"text/css\"></style><span style=\"font-family:Calibri,Arial;font-size:12pt;\"><i><span style=\"font-weight:normal;\" data-sheets-root=\"1\">Ask me a question.</span></i></span></p>','<p><style type=\"text/css\"></style><span style=\"color:#0d0d0d;font-family:Calibri,Arial;font-size:12pt;\"><span style=\"font-style:normal;font-weight:normal;\" data-sheets-root=\"1\">Hãy <strong>hỏi </strong>tôi một câu hỏi.</span></span></p>','/uploads/2024/08/12/1723457573_tro ly van phong.jpg','/uploads/2024/07/26/1722016481_again.mp3',NULL,'WORD','answer'),
(10,'1.Short form: I\'m/am,  \'re/are','1.Short form: I\'m/am,  \'re/are',1,NULL,'2024-08-17 08:08:07','2024-08-17 09:15:08','1.Short form: I\'m/am,  \'re/are','1.Short form: I\'m/am,  \'re/are','1.Short form: I\'m/am,  \'re/are','<figure class=\"table\"><table class=\"ck-table-resized\" style=\"border-collapse:collapse;font-family:Arial;font-size:10pt;table-layout:fixed;\" cellspacing=\"0\" cellpadding=\"0\" dir=\"ltr\" border=\"1\" data-sheets-root=\"1\" data-sheets-baot=\"1\"><colgroup><col style=\"width:100%;\" width=\"301\"></colgroup><tbody><tr style=\"height:21px;\"><td style=\"border:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\"><span style=\"font-family:Arial;font-size:10pt;\"><span style=\"font-style:normal;\"><strong>1.1 Use</strong></span><i><strong> \'m</strong></i><span style=\"font-style:normal;\"><strong> or&nbsp;</strong></span><i><strong>\'re&nbsp;</strong></i><span style=\"font-style:normal;\"><strong>for speaking:</strong></span></span></td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">I am = I\'m</td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">You are = You\'re</td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\"><span style=\"font-family:Arial;font-size:10pt;\"><span style=\"font-style:normal;\"><strong>1.2 Use&nbsp;</strong></span><i><strong>am</strong></i><span style=\"font-style:normal;\"><strong> for short answers:</strong></span></span></td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">Are you the director of this company?</td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">Yes, I am.</td></tr></tbody></table></figure><p>Check <strong>English</strong></p>','<figure class=\"table\"><table class=\"ck-table-resized\" style=\"border-collapse:collapse;font-family:Arial;font-size:10pt;table-layout:fixed;\" cellspacing=\"0\" cellpadding=\"0\" dir=\"ltr\" border=\"1\" data-sheets-root=\"1\" data-sheets-baot=\"1\"><colgroup><col style=\"width:100%;\" width=\"352\"></colgroup><tbody><tr style=\"height:21px;\"><td style=\"border:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\"><span style=\"font-family:Arial;font-size:10pt;\"><span style=\"font-style:normal;\"><strong>1.1 Sử dụng</strong></span><i><strong> \'m</strong></i><span style=\"font-style:normal;\"><strong> hoặc</strong></span><i><strong> \'re</strong></i><span style=\"font-style:normal;\"><strong> khi nói:</strong></span></span></td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">I am = i\'m : Tôi là&nbsp;</td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">You are = you\'re : Bạn là&nbsp;</td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\"><span style=\"font-family:Arial;font-size:10pt;\"><span style=\"font-style:normal;\"><strong>1.2 Sử dụng</strong></span><i><strong> am</strong></i><span style=\"font-style:normal;\"><strong> cho những câu trả lời ngắn&nbsp;</strong></span></span></td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">Bạn là giám đốc công ty này phải không?</td></tr><tr style=\"height:21px;\"><td style=\"border-bottom:1px solid #000000;border-left:1px solid #000000;border-right:1px solid #000000;overflow:hidden;padding:2px 3px;vertical-align:bottom;\">Đúng vậy, tôi là giám đốc công ty này.</td></tr></tbody></table></figure><p>Check <i>tiếng Việt</i></p>',NULL,NULL,NULL,'GRAMMAR','1.Short form: I\'m/am,  \'re/are');
